#include<bits/stdc++.h>
using namespace std;
int dp[2010],a[1010][1010],b[1010];
int main()
{
    int n,m,p;
    scanf("%d%d%d",&n,&m,&p);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
        }
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&b[i]);
    }
    memset(dp,-0x3f,sizeof(dp));
    dp[0]=0;
    for(int i=1;i<=m;i++)
    {
        for(int j=1;j<=n;j++)
        {
            int sum=dp[i-1]-b[j];
            for(int k=0;k<p&&i+k<=m;k++)
            {
                int pos=j+k;
                if(pos>n)
                {
                    pos-=n;
                }
                sum+=a[pos][i+k];
                dp[i+k]=max(dp[i+k],sum);
            }
        }
    }
    printf("%d",dp[m]);
    return 0;
}
